"""requests.sessions — Session implementation using urllib."""
import json as _json
import io
import gzip
from urllib.request import Request as UrllibRequest, urlopen, build_opener, HTTPCookieProcessor
from urllib.parse import urlencode, urlparse, urljoin
from urllib.error import HTTPError as UrllibHTTPError, URLError
from http.cookiejar import CookieJar
import time

from requests.models import Response, PreparedRequest
from requests.structures import CaseInsensitiveDict
from requests.utils import default_headers
from requests import exceptions


class Session:
    def __init__(self):
        self.headers = default_headers()
        self.cookies = CookieJar()
        self.auth = None
        self.verify = True
        self.timeout = 30
        self.max_redirects = 30

    def request(self, method, url, params=None, data=None, headers=None,
                json=None, timeout=None, auth=None, cookies=None,
                allow_redirects=True, stream=False, files=None, **kwargs):
        # Build URL with query params
        if params:
            sep = "&" if "?" in url else "?"
            if isinstance(params, dict):
                url = url + sep + urlencode(params)
            elif isinstance(params, str):
                url = url + sep + params

        # Prepare body
        body = None
        content_type = None
        if json is not None:
            body = _json.dumps(json).encode("utf-8")
            content_type = "application/json"
        elif data is not None:
            if isinstance(data, dict):
                body = urlencode(data).encode("utf-8")
                content_type = "application/x-www-form-urlencoded"
            elif isinstance(data, str):
                body = data.encode("utf-8")
            elif isinstance(data, bytes):
                body = data

        # Merge headers
        merged = CaseInsensitiveDict(self.headers)
        if headers:
            for k, v in headers.items():
                merged[k] = v
        if content_type and "content-type" not in merged:
            merged["content-type"] = content_type

        # Auth
        req_auth = auth or self.auth
        prep = PreparedRequest()
        prep.method = method.upper()
        prep.url = url
        prep.headers = merged
        prep.body = body
        if req_auth and callable(req_auth):
            req_auth(prep)

        # Build urllib request
        req = UrllibRequest(
            prep.url,
            data=prep.body,
            headers=dict(prep.headers),
            method=prep.method,
        )

        # Execute
        t0 = time.monotonic()
        resp = Response()
        resp.request = prep
        resp.url = url

        _timeout = timeout or self.timeout
        try:
            opener = build_opener(HTTPCookieProcessor(self.cookies))
            http_resp = opener.open(req, timeout=_timeout)
            resp.status_code = http_resp.status
            resp.reason = http_resp.reason or ""
            resp.url = http_resp.url or url
            # Headers
            for key, val in http_resp.headers.items():
                resp.headers[key] = val
            # Content
            raw = http_resp.read()
            # Decompress gzip
            if resp.headers.get("content-encoding", "").lower() == "gzip":
                try:
                    raw = gzip.decompress(raw)
                except Exception:
                    pass
            resp._content = raw
            # Encoding
            ct = resp.headers.get("content-type", "")
            if "charset=" in ct:
                resp.encoding = ct.split("charset=")[-1].split(";")[0].strip()
            http_resp.close()
        except UrllibHTTPError as e:
            resp.status_code = e.code
            resp.reason = e.reason or ""
            try:
                resp._content = e.read()
            except Exception:
                resp._content = b""
            for key, val in e.headers.items():
                resp.headers[key] = val
        except URLError as e:
            raise exceptions.ConnectionError(str(e.reason))
        except TimeoutError:
            raise exceptions.Timeout(f"Request timed out ({_timeout}s)")
        except Exception as e:
            raise exceptions.RequestException(str(e))

        resp.elapsed = time.monotonic() - t0
        return resp

    def get(self, url, **kwargs):
        return self.request("GET", url, **kwargs)

    def post(self, url, data=None, json=None, **kwargs):
        return self.request("POST", url, data=data, json=json, **kwargs)

    def put(self, url, data=None, **kwargs):
        return self.request("PUT", url, data=data, **kwargs)

    def delete(self, url, **kwargs):
        return self.request("DELETE", url, **kwargs)

    def head(self, url, **kwargs):
        return self.request("HEAD", url, **kwargs)

    def options(self, url, **kwargs):
        return self.request("OPTIONS", url, **kwargs)

    def patch(self, url, data=None, **kwargs):
        return self.request("PATCH", url, data=data, **kwargs)

    def close(self):
        pass

    def __enter__(self):
        return self

    def __exit__(self, *args):
        self.close()
